CREATE TABLE "AcarsSession" ("id" TEXT NOT NULL,"localSessionId" TEXT NOT NULL,"pilotId" TEXT NOT NULL,"bookingId" TEXT NOT NULL,"flightId" TEXT NOT NULL,"dispatchId" TEXT NOT NULL,"dispatchVersion" INTEGER NOT NULL,"aircraftId" TEXT NOT NULL,"simulatorName" TEXT NOT NULL,"acarsVersion" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"currentPhase" TEXT NOT NULL DEFAULT 'Preflight',"startedAt" TIMESTAMP(3) NOT NULL,"lastHeartbeatAt" TIMESTAMP(3) NOT NULL,"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AcarsSession_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AcarsPosition" ("id" TEXT NOT NULL,"sessionId" TEXT NOT NULL,"sequenceNumber" INTEGER NOT NULL,"recordedAt" TIMESTAMP(3) NOT NULL,"latitude" DOUBLE PRECISION,"longitude" DOUBLE PRECISION,"altitudeFeet" DOUBLE PRECISION,"groundSpeedKnots" DOUBLE PRECISION,"headingDegrees" DOUBLE PRECISION,"fuelKg" DOUBLE PRECISION,"onGround" BOOLEAN,"phase" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AcarsPosition_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AcarsEvent" ("id" TEXT NOT NULL,"sessionId" TEXT NOT NULL,"sequenceNumber" INTEGER NOT NULL,"type" TEXT NOT NULL,"recordedAt" TIMESTAMP(3) NOT NULL,"phaseBefore" TEXT,"phaseAfter" TEXT,"message" TEXT,"latitude" DOUBLE PRECISION,"longitude" DOUBLE PRECISION,"altitudeFeet" DOUBLE PRECISION,"groundSpeedKnots" DOUBLE PRECISION,"fuelKg" DOUBLE PRECISION,"numericValue" DOUBLE PRECISION,"textValue" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AcarsEvent_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "AcarsSession_localSessionId_key" ON "AcarsSession"("localSessionId"); CREATE UNIQUE INDEX "AcarsSession_dispatchId_key" ON "AcarsSession"("dispatchId"); CREATE INDEX "AcarsSession_pilotId_status_idx" ON "AcarsSession"("pilotId","status"); CREATE INDEX "AcarsSession_flightId_status_idx" ON "AcarsSession"("flightId","status");
CREATE UNIQUE INDEX "AcarsPosition_sessionId_sequenceNumber_key" ON "AcarsPosition"("sessionId","sequenceNumber"); CREATE INDEX "AcarsPosition_recordedAt_idx" ON "AcarsPosition"("recordedAt");
CREATE UNIQUE INDEX "AcarsEvent_sessionId_sequenceNumber_key" ON "AcarsEvent"("sessionId","sequenceNumber"); CREATE INDEX "AcarsEvent_recordedAt_idx" ON "AcarsEvent"("recordedAt");
ALTER TABLE "AcarsPosition" ADD CONSTRAINT "AcarsPosition_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "AcarsSession"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "AcarsEvent" ADD CONSTRAINT "AcarsEvent_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "AcarsSession"("id") ON DELETE CASCADE ON UPDATE CASCADE;
